const body = $input.first().json.body || {};
const contactId = String(body.contactId || '').trim();
const base64 = String(body.base64 || '').trim();
const fileName = String(body.fileName || 'archivo').trim().replace(/[^a-zA-Z0-9._-]/g, '_').slice(0, 100);
const mimeType = String(body.mimeType || 'application/octet-stream').trim().slice(0, 120);
const caption = String(body.caption || '').trim().slice(0, 1024);
const userName = String(body.userName || 'Administrador CRM').trim().slice(0, 120);
const validId = /^[A-Za-z0-9_-]{1,128}$/.test(contactId);
const validB64 = base64.length > 10;
if (!validId || !validB64) {
  return [{ json: { ok: false, status: 400, error: 'Payload invalido (contactId/base64)' } }];
}
return [{ json: { ok: true, contactId, base64, fileName, mimeType, caption, userName } }];

const fs = require('fs');

const item = $input.first().json;
const base64 = item.base64;
const fileName = item.fileName;
const contactId = item.contactId;
const userName = item.userName;
const mimeType = item.mimeType;
const caption = item.caption || '';

const timestamp = Date.now();
const random = Math.random().toString(36).substring(2, 10);
const safeFileName = timestamp + '-' + random + '-' + fileName.replace(/[^a-zA-Z0-9._-]/g, '_');
const filePath = '/var/www/media/' + safeFileName;
const mediaUrl = 'https://crm.cuentastupana.com/media/' + safeFileName;

const buffer = Buffer.from(base64, 'base64');
fs.writeFileSync(filePath, buffer);
fs.chmodSync(filePath, 0o644);

console.log('MEDIA: guardado en', filePath, '| url:', mediaUrl);

return [{ json: { contactId, mediaUrl, mimeType, fileName: safeFileName, caption, userName } }];
